using UnityEngine;

/// <summary>
/// Baú — ao "abrir" (recolher, como qualquer outro pickup, via
/// <c>OnTriggerEnter2D</c> ou chamada directa a <see cref="PickupBase.Collect"/>
/// a partir de uma interacção), entrega o conteúdo configurado
/// (<see cref="loot"/> + <see cref="sementes"/>, via <c>PlayerProgress.AddItem</c>
/// / <c>GiveSementes</c>) e regista "baú aberto" na área
/// (<c>AreaProgress.chestsFound</c> / <c>AreaData.totalChests</c>).
///
/// Nota: este componente não implementa por si só um botão de "interagir" —
/// se o design quiser que o baú só abra ao apertar Interagir (em vez de
/// trigger automático), bastar reescrever <see cref="PickupBase.OnTriggerEnter2D"/>
/// nesta subclasse para apenas marcar "ao alcance" e chamar
/// <c>Collect()</c> a partir do botão de interacção do player.
/// </summary>
public class ChestPickup : PickupBase
{
    [Header("Conteúdo do Baú")]
    [Tooltip("Itens entregues ao abrir (PlayerProgress.AddItem — respeita ItemData.maxQuantity / savedAsCollected).")]
    public PickupLootEntry[] loot;

    [Tooltip("Sementes adicionais dentro do baú (0 = nenhuma).")]
    [Min(0)] public int sementes = 0;

    public override PickupType Type => PickupType.Chest;

    protected override void GrantReward()
    {
        var progress = PlayerProgress.Instance;
        if (progress == null) return;

        if (loot != null)
        {
            foreach (var entry in loot)
            {
                if (entry == null || entry.item == null) continue;
                progress.AddItem(entry.item, entry.amount);
            }
        }

        if (sementes > 0) progress.GiveSementes(sementes);

        if (area != null) progress.AddChestFound(area);
    }
}
